/**
 * Execute arbitrary JavaScript code and capture its console output
 * @param {string} codeString - JavaScript code to execute
 * @returns {string} The captured console output
 */
function executeCode(codeString) {
  // Save the original console.log function
  const originalLog = console.log;

  // Create an array to store the output
  const outputLines = [];

  // Override console.log to capture output
  console.log = function(...args) {
    // Convert all arguments to strings and join them
    const output = args.map(arg => 
      typeof arg === 'object' ? JSON.stringify(arg) : String(arg)
    ).join(' ');

    // Add to our captured output
    outputLines.push(output);
  };

  // Variable to store the result
  let result;

  try {
    // Execute the code
    result = eval(codeString);
  } catch (error) {
    // Restore the original console.log
    console.log = originalLog;
    return `Error executing code: ${error.message}`;
  } finally {
    // Restore the original console.log
    console.log = originalLog;
  }

  // Join all captured output lines
  const output = outputLines.join('\n');

  // If there's a result but no console output, return the result
  if (output === '' && result !== undefined) {
    return String(result);
  }

  return output;
}

return executeCode(query.code_to_execute);

/**
 * Calculate BMR, TDEE, and macro targets with automatic goal inference
 * @param {Object} params - {age, gender, weight_kg, height_cm, activity_level, goals, activities}
 * @returns {Object} Nutritional targets
 */

const params = query;

// Input validation
const required = ['age', 'gender', 'weight_kg', 'height_cm', 'activity_level'];
for (const field of required) {
  if (!params[field]) {
    return JSON.stringify({error: `Missing required field: ${field}`});
  }
}

const { 
  age, 
  gender, 
  weight_kg, 
  height_cm, 
  activity_level, 
  goals = {},
  activities = [],  // NEW: ["musculation", "basket", "cardio", etc.]
  context = ""      // NEW: free text like "je fais de la musculation et du basket"
} = params;

// ============================================
// AUTO-INFERENCE OF GOALS FROM ACTIVITIES/CONTEXT
// ============================================

let inferredGoals = {
  weight_loss: goals.weight_loss || goals.perte_poids || 0,
  muscle_gain: goals.muscle_gain || goals.prise_muscle || 0,
  performance: goals.performance || 0,
  maintenance: goals.maintenance || goals.maintien || 5
};

// Normalize activities to lowercase array
let activityList = [];
if (Array.isArray(activities)) {
  activityList = activities.map(a => a.toLowerCase().trim());
}

// Parse context string for activity keywords
const contextLower = context.toLowerCase();

// Activity detection patterns
const muscleKeywords = ['musculation', 'muscu', 'force', 'strength', 'haltères', 'poids', 'gym', 'bodybuilding', 'hypertrophie'];
const teamSportKeywords = ['basket', 'basketball', 'foot', 'football', 'rugby', 'handball', 'volley', 'volleyball', 'hockey'];
const cardioKeywords = ['cardio', 'course', 'running', 'vélo', 'cyclisme', 'natation', 'swimming', 'rameur', 'hiit'];
const weightLossKeywords = ['perdre', 'perte', 'maigrir', 'sécher', 'sèche', 'déficit', 'mincir', 'régime'];
const bulkKeywords = ['prendre', 'masse', 'bulk', 'grossir', 'gain', 'prise de masse'];

// Check activities array
const hasMuscle = activityList.some(a => muscleKeywords.some(k => a.includes(k)));
const hasTeamSport = activityList.some(a => teamSportKeywords.some(k => a.includes(k)));
const hasCardio = activityList.some(a => cardioKeywords.some(k => a.includes(k)));

// Check context string
const contextHasMuscle = muscleKeywords.some(k => contextLower.includes(k));
const contextHasTeamSport = teamSportKeywords.some(k => contextLower.includes(k));
const contextHasCardio = cardioKeywords.some(k => contextLower.includes(k));
const contextHasWeightLoss = weightLossKeywords.some(k => contextLower.includes(k));
const contextHasBulk = bulkKeywords.some(k => contextLower.includes(k));

// Infer goals based on detected activities
let goalsInferred = false;
let inferenceRationale = [];

// Musculation detected
if (hasMuscle || contextHasMuscle) {
  if (inferredGoals.muscle_gain < 6) {
    inferredGoals.muscle_gain = 7;
    goalsInferred = true;
    inferenceRationale.push("Musculation détectée → muscle_gain: 7");
  }
  if (inferredGoals.performance < 4) {
    inferredGoals.performance = 5;
    inferenceRationale.push("Musculation détectée → performance: 5");
  }
}

// Team sport detected
if (hasTeamSport || contextHasTeamSport) {
  if (inferredGoals.performance < 7) {
    inferredGoals.performance = 7;
    goalsInferred = true;
    inferenceRationale.push("Sport collectif détecté → performance: 7");
  }
  if (inferredGoals.muscle_gain < 5) {
    inferredGoals.muscle_gain = 5;
    inferenceRationale.push("Sport collectif détecté → muscle_gain: 5");
  }
}

// Both muscle + team sport = high goals
if ((hasMuscle || contextHasMuscle) && (hasTeamSport || contextHasTeamSport)) {
  inferredGoals.muscle_gain = Math.max(inferredGoals.muscle_gain, 7);
  inferredGoals.performance = Math.max(inferredGoals.performance, 7);
  inferenceRationale.push("Musculation + Sport collectif → objectifs élevés (7/7)");
}

// Cardio detected
if (hasCardio || contextHasCardio) {
  if (inferredGoals.performance < 6) {
    inferredGoals.performance = 6;
    goalsInferred = true;
    inferenceRationale.push("Cardio détecté → performance: 6");
  }
}

// Weight loss intent
if (contextHasWeightLoss) {
  inferredGoals.weight_loss = Math.max(inferredGoals.weight_loss, 7);
  goalsInferred = true;
  inferenceRationale.push("Intention perte de poids détectée → weight_loss: 7");
}

// Bulk intent
if (contextHasBulk) {
  inferredGoals.muscle_gain = Math.max(inferredGoals.muscle_gain, 8);
  goalsInferred = true;
  inferenceRationale.push("Intention prise de masse détectée → muscle_gain: 8");
}

// Reduce maintenance if other goals are high
if (inferredGoals.muscle_gain > 5 || inferredGoals.weight_loss > 5 || inferredGoals.performance > 5) {
  inferredGoals.maintenance = 2;
}

// ============================================
// 1. BMR - Mifflin-St Jeor Formula
// ============================================
let bmr;
if (gender.toLowerCase() === 'male' || gender.toLowerCase() === 'm' || gender.toLowerCase() === 'homme') {
  bmr = (10 * weight_kg) + (6.25 * height_cm) - (5 * age) + 5;
} else {
  bmr = (10 * weight_kg) + (6.25 * height_cm) - (5 * age) - 161;
}

// ============================================
// 2. TDEE - Activity Level with smart adjustment
// ============================================
const activityMultipliers = {
  'sedentary': 1.2,
  'sédentaire': 1.2,
  'light': 1.375,
  'léger': 1.375,
  'moderate': 1.55,
  'modéré': 1.55,
  'modérée': 1.55,
  'active': 1.725,
  'actif': 1.725,
  'very_active': 1.9,
  'très_actif': 1.9,
  'tres_actif': 1.9
};

let activityKey = activity_level.toLowerCase().trim();
let multiplier = activityMultipliers[activityKey] || 1.55;

// Smart adjustment: if sedentary job + daily sport mentioned, bump up
const hasDailySport = contextLower.includes('jour') || contextLower.includes('daily') || 
                       contextLower.includes('quotidien') || contextLower.includes('séance');
const isSedentaryBase = activityKey === 'sedentary' || activityKey === 'sédentaire' || activityKey === 'light' || activityKey === 'léger';

if (isSedentaryBase && hasDailySport && (hasMuscle || contextHasMuscle || hasTeamSport || contextHasTeamSport)) {
  multiplier = 1.55; // Bump to moderate
  activityKey = "moderate (ajusté: sédentaire + sport quotidien)";
  inferenceRationale.push("Travail sédentaire + sport quotidien → activité ajustée à moderate (1.55)");
}

const tdee = bmr * multiplier;

// ============================================
// 3. Calorie Target Based on Goals
// ============================================
const weightLoss = inferredGoals.weight_loss;
const muscleGain = inferredGoals.muscle_gain;
const performance = inferredGoals.performance;

let targetCalories = tdee;
let calorieAdjustment = 0;
let calorieRationale = "Maintien";

if (weightLoss > 6) {
  calorieAdjustment = -500;
  calorieRationale = "Déficit agressif pour perte de poids";
} else if (weightLoss > 3) {
  calorieAdjustment = -300;
  calorieRationale = "Déficit modéré pour perte de poids";
} else if (muscleGain > 6) {
  calorieAdjustment = +300;
  calorieRationale = "Surplus pour prise de muscle";
} else if (muscleGain > 3) {
  calorieAdjustment = +150;
  calorieRationale = "Surplus léger pour prise de muscle sèche";
}

targetCalories = tdee + calorieAdjustment;

// Safety limits
const minCalories = (gender.toLowerCase() === 'female' || gender.toLowerCase() === 'femme' || gender.toLowerCase() === 'f') ? 1200 : 1500;
targetCalories = Math.max(targetCalories, minCalories);

// ============================================
// 4. PROTEIN - Scientific approach (g/kg)
// ============================================
let proteinPerKg = 1.6;
let proteinRationale = "Base maintien (1.6g/kg)";

if (muscleGain > 7 || performance > 7) {
  proteinPerKg = 2.2;
  proteinRationale = "Maximum scientifique pour hypertrophie/performance (2.2g/kg - ISSN)";
} else if (muscleGain > 5 || performance > 5) {
  proteinPerKg = 2.0;
  proteinRationale = "Optimisé pour muscle/performance (2.0g/kg)";
} else if (muscleGain > 3 || performance > 3) {
  proteinPerKg = 1.8;
  proteinRationale = "Modéré pour activité sportive (1.8g/kg)";
} else if (weightLoss > 5) {
  proteinPerKg = 2.0;
  proteinRationale = "Élevé pour préserver la masse musculaire en déficit (2.0g/kg)";
} else if (weightLoss > 3) {
  proteinPerKg = 1.8;
  proteinRationale = "Modéré pour satiété en déficit (1.8g/kg)";
}

const targetProtein = Math.round(weight_kg * proteinPerKg);
const proteinCalories = targetProtein * 4;
const actualProteinPercent = Math.round((proteinCalories / targetCalories) * 100);

// ============================================
// 5. FAT - Essential for hormones
// ============================================
let fatPercent = 0.25;
let fatRationale = "Standard (25%)";

if (weightLoss > 7) {
  fatPercent = 0.20;
  fatRationale = "Réduit en déficit (20%)";
}

const fatCalories = targetCalories * fatPercent;
const targetFat = Math.round(fatCalories / 9);

// ============================================
// 6. CARBS - Remaining calories
// ============================================
const carbCalories = targetCalories - proteinCalories - fatCalories;
const targetCarbs = Math.round(carbCalories / 4);
const actualCarbsPercent = Math.round((carbCalories / targetCalories) * 100);
const actualFatPercent = Math.round((fatCalories / targetCalories) * 100);

let carbsRationale = "Calories restantes pour l'énergie";
if (performance > 5) {
  carbsRationale = "Priorité glucides pour performance sportive";
}

// ============================================
// 7. Warnings
// ============================================
const warnings = [];

if (targetCarbs < 100) {
  warnings.push("⚠️ Glucides bas (<100g) - peut affecter l'énergie");
}
if (targetFat < 50) {
  warnings.push("⚠️ Lipides très bas (<50g) - peut affecter les hormones");
}

// ============================================
// 8. Return results
// ============================================
return JSON.stringify({
  bmr: Math.round(bmr),
  tdee: Math.round(tdee),
  target_calories: Math.round(targetCalories),

  target_protein_g: targetProtein,
  target_carbs_g: targetCarbs,
  target_fat_g: targetFat,

  macros_percentage: {
    protein: actualProteinPercent,
    carbs: actualCarbsPercent,
    fat: actualFatPercent
  },

  protein_per_kg: proteinPerKg,

  rationale: {
    calories: calorieRationale,
    protein: proteinRationale,
    carbs: carbsRationale,
    fat: fatRationale
  },

  activity_multiplier: multiplier,
  activity_level_used: activityKey,

  goals_used: inferredGoals,
  goals_were_inferred: goalsInferred,
  inference_rationale: inferenceRationale.length > 0 ? inferenceRationale : ["Aucune inférence - objectifs explicites ou défaut"],

  warnings: warnings.length > 0 ? warnings : ["✅ Paramètres dans les normes"],

  summary: `BMR: ${Math.round(bmr)} | TDEE: ${Math.round(tdee)} | Cible: ${Math.round(targetCalories)} kcal | P: ${targetProtein}g (${proteinPerKg}g/kg) | G: ${targetCarbs}g | L: ${targetFat}g`

}, null, 2);

/**
 * Calculate weekly nutritional adjustments based on feedback
 * @param {Object} params - Weekly tracking data
 * @returns {Object} Recommended adjustments
 */

const params = query;

// Input validation
const required = ['weight_start', 'weight_end', 'current_calories'];
for (const field of required) {
  if (params[field] === undefined || params[field] === null) {
    return JSON.stringify({error: `Missing required field: ${field}`});
  }
}

const {
  weight_start,
  weight_end,
  current_calories,
  current_protein_g = 0,
  current_carbs_g = 0,
  current_fat_g = 0,
  adherence_rate = 100,
  hunger_level = "medium",      // low, medium, high
  energy_level = "medium",      // low, medium, high
  sleep_quality = "medium",     // poor, medium, good
  cravings = [],                // ["sucré", "salé", "gras"]
  user_goal = "maintenance",    // weight_loss, muscle_gain, maintenance, performance
  weeks_on_plan = 1,
  notes = ""                    // Free text feedback
} = params;

// Calculate weight change
const weight_change = weight_end - weight_start;
const weight_change_percent = ((weight_change / weight_start) * 100).toFixed(2);

// Initialize adjustments
let calorie_adjustment = 0;
let protein_adjustment = 0;
let carbs_adjustment = 0;
let fat_adjustment = 0;

const rationale = [];
const alerts = [];
const warnings = [];
const tips = [];

// ============================================
// 1. ADHERENCE CHECK (Priority)
// ============================================
if (adherence_rate < 50) {
  alerts.push("🚨 Adhérence très faible (<50%) - Le plan actuel est peut-être trop restrictif");
  rationale.push("Adhérence insuffisante - priorité: simplifier le plan et améliorer le suivi");
  tips.push("Essaie de préparer tes repas à l'avance (meal prep)");
  tips.push("Commence par suivre 1-2 repas par jour avant d'augmenter");

  return JSON.stringify({
    status: "adherence_issue",
    adjustments: { calories: 0, protein_g: 0, carbs_g: 0, fat_g: 0 },
    new_targets: {
      calories: current_calories,
      protein_g: current_protein_g,
      carbs_g: current_carbs_g,
      fat_g: current_fat_g
    },
    weight_analysis: {
      start_kg: weight_start,
      end_kg: weight_end,
      change_kg: parseFloat(weight_change.toFixed(2)),
      change_percent: parseFloat(weight_change_percent),
      trend: "inconnu (adhérence insuffisante)"
    },
    rationale: rationale,
    alerts: alerts,
    warnings: ["Améliorer l'adhérence avant d'ajuster les apports"],
    tips: tips,
    recommendation: "🎯 Focus cette semaine: suivre le plan à 70%+ avant tout ajustement",
    next_check: "Réévaluation après une semaine d'adhérence améliorée"
  }, null, 2);
}

if (adherence_rate < 70) {
  warnings.push("⚠️ Adhérence modérée (50-70%) - Les ajustements seront conservateurs");
  rationale.push("Adhérence à améliorer - ajustements limités cette semaine");
}

// ============================================
// 2. WEIGHT ANALYSIS BY GOAL
// ============================================
const goalLower = user_goal.toLowerCase();

if (goalLower === "weight_loss" || goalLower === "perte_poids" || goalLower === "perte") {

  // Target: -0.3 to -0.7 kg/week (safe loss = 0.5-1% body weight)
  if (weight_change < -1.0) {
    calorie_adjustment += 200;
    rationale.push(`⚠️ Perte trop rapide (${weight_change.toFixed(2)}kg/sem) → +200 kcal pour préserver les muscles`);
    warnings.push("Perte >1kg/semaine = risque de perte musculaire");
    tips.push("Une perte de 0.5-0.7kg/semaine est optimale pour préserver la masse musculaire");

  } else if (weight_change < -0.7) {
    calorie_adjustment += 100;
    rationale.push(`Perte rapide (${weight_change.toFixed(2)}kg) → +100 kcal par sécurité`);

  } else if (weight_change >= -0.3 && weight_change < 0) {
    rationale.push(`✅ Perte optimale (${weight_change.toFixed(2)}kg) - Continue ainsi !`);

  } else if (weight_change >= 0 && weight_change < 0.3) {
    calorie_adjustment -= 150;
    rationale.push(`Stagnation (${weight_change.toFixed(2)}kg) → -150 kcal pour relancer`);
    tips.push("Vérifie aussi ton niveau d'activité et la qualité du sommeil");

  } else if (weight_change >= 0.3) {
    calorie_adjustment -= 250;
    rationale.push(`❌ Prise de poids (${weight_change.toFixed(2)}kg) en objectif perte → -250 kcal`);
    alerts.push("🚨 Prise de poids alors qu'objectif = perte");
    tips.push("Revérifie les portions et les calories cachées (sauces, huiles, snacks)");
  }

} else if (goalLower === "muscle_gain" || goalLower === "prise_muscle" || goalLower === "prise" || goalLower === "masse") {

  // Target: +0.2 to +0.5 kg/week (lean gain)
  if (weight_change > 0.7) {
    calorie_adjustment -= 200;
    rationale.push(`⚠️ Prise trop rapide (${weight_change.toFixed(2)}kg) → -200 kcal pour limiter le gras`);
    warnings.push("Prise >0.7kg/semaine = probablement du gras");

  } else if (weight_change > 0.5) {
    calorie_adjustment -= 100;
    rationale.push(`Prise légèrement rapide (${weight_change.toFixed(2)}kg) → -100 kcal`);

  } else if (weight_change >= 0.2 && weight_change <= 0.5) {
    rationale.push(`✅ Prise optimale (${weight_change.toFixed(2)}kg) - Parfait pour une prise sèche !`);

  } else if (weight_change >= 0 && weight_change < 0.2) {
    calorie_adjustment += 150;
    rationale.push(`Prise lente (${weight_change.toFixed(2)}kg) → +150 kcal`);

  } else if (weight_change < 0) {
    calorie_adjustment += 300;
    rationale.push(`❌ Perte de poids (${weight_change.toFixed(2)}kg) en objectif prise → +300 kcal`);
    alerts.push("🚨 Tu perds du poids alors que tu veux en prendre");
    tips.push("Ajoute une collation ou augmente les portions");
  }

} else if (goalLower === "performance" || goalLower === "sport") {

  // Performance: slight surplus, stable weight OK
  if (Math.abs(weight_change) <= 0.3) {
    rationale.push(`✅ Poids stable (${weight_change.toFixed(2)}kg) - Idéal pour la performance`);
  } else if (weight_change < -0.5) {
    calorie_adjustment += 200;
    rationale.push(`Perte de poids (${weight_change.toFixed(2)}kg) → +200 kcal pour maintenir l'énergie`);
    warnings.push("Déficit calorique peut impacter tes performances");
  } else if (weight_change > 0.5) {
    calorie_adjustment -= 100;
    rationale.push(`Prise de poids (${weight_change.toFixed(2)}kg) → -100 kcal`);
  }

} else {
  // Maintenance
  if (Math.abs(weight_change) <= 0.3) {
    rationale.push(`✅ Poids stable (${weight_change.toFixed(2)}kg) - Maintien réussi`);
  } else {
    const adj = weight_change > 0 ? -100 : +100;
    calorie_adjustment += adj;
    rationale.push(`Variation (${weight_change.toFixed(2)}kg) → ${adj > 0 ? '+' : ''}${adj} kcal pour stabiliser`);
  }
}

// ============================================
// 3. HUNGER ANALYSIS
// ============================================
const hungerLower = hunger_level.toLowerCase();

if (hungerLower === "high" || hungerLower === "élevé" || hungerLower === "élevée" || hungerLower === "forte") {
  protein_adjustment += 20;
  rationale.push("🍽️ Faim élevée → +20g protéines pour améliorer la satiété");
  tips.push("Privilégie les aliments riches en fibres et protéines");
  tips.push("Bois plus d'eau, parfois la soif est confondue avec la faim");

  // If also losing weight fast, add more calories
  if (weight_change < -0.5 && (goalLower === "weight_loss" || goalLower === "perte_poids")) {
    calorie_adjustment += 100;
    rationale.push("Faim + perte rapide → +100 kcal supplémentaires");
  }

} else if (hungerLower === "low" || hungerLower === "faible" || hungerLower === "basse") {
  rationale.push("✅ Faim bien gérée");

  // If not hungry but not losing weight in weight loss goal
  if (weight_change >= 0 && (goalLower === "weight_loss" || goalLower === "perte_poids")) {
    tips.push("Tu n'as pas faim mais tu ne perds pas - vérifie les calories liquides et les snacks");
  }
}

// ============================================
// 4. ENERGY ANALYSIS
// ============================================
const energyLower = energy_level.toLowerCase();

if (energyLower === "low" || energyLower === "faible" || energyLower === "basse") {
  carbs_adjustment += 30;
  rationale.push("⚡ Énergie basse → +30g glucides");
  tips.push("Place tes glucides autour de l'entraînement (avant et après)");
  tips.push("Vérifie ton sommeil et ton hydratation");

  if (sleep_quality === "poor" || sleep_quality === "mauvais" || sleep_quality === "mauvaise") {
    warnings.push("Énergie basse + mauvais sommeil - le sommeil est prioritaire");
    tips.push("Vise 7-9h de sommeil de qualité avant d'ajuster la nutrition");
  }

} else if (energyLower === "high" || energyLower === "élevé" || energyLower === "élevée" || energyLower === "haute") {
  rationale.push("✅ Niveau d'énergie optimal");
}

// ============================================
// 5. SLEEP QUALITY IMPACT
// ============================================
const sleepLower = (sleep_quality || "medium").toLowerCase();

if (sleepLower === "poor" || sleepLower === "mauvais" || sleepLower === "mauvaise") {
  warnings.push("😴 Mauvais sommeil détecté - peut ralentir le métabolisme de 5-10%");
  tips.push("Le manque de sommeil augmente la ghréline (hormone de la faim)");
  tips.push("Priorité #1: améliorer le sommeil avant d'ajuster les calories");
}

// ============================================
// 6. CRAVINGS MANAGEMENT
// ============================================
const cravingsLower = Array.isArray(cravings) ? cravings.map(c => c.toLowerCase()) : [];

if (cravingsLower.includes("sucré") || cravingsLower.includes("sucre") || cravingsLower.includes("sweet")) {
  rationale.push("🍬 Fringales sucrées détectées");
  tips.push("Intègre 1 fruit ou 1 carré de chocolat noir après le repas");
  tips.push("Les fringales sucrées peuvent indiquer un manque de glucides ou de sommeil");
  alerts.push("💡 Suggestion: yaourt grec + miel, fruits, chocolat noir 70%+");
}

if (cravingsLower.includes("salé") || cravingsLower.includes("sel") || cravingsLower.includes("salty")) {
  rationale.push("🧂 Fringales salées détectées");
  tips.push("Vérifie ton hydratation - bois-tu assez d'eau?");
  tips.push("Après le sport, un peu de sel est normal et bénéfique");
  alerts.push("💡 Suggestion: cornichons, olives, bouillon, oléagineux légèrement salés");
}

if (cravingsLower.includes("gras") || cravingsLower.includes("fat") || cravingsLower.includes("fatty")) {
  fat_adjustment += 10;
  rationale.push("🥑 Fringales grasses → +10g lipides");
  tips.push("Ajoute des sources de bons gras: avocat, huile d'olive, noix");
  alerts.push("💡 Suggestion: avocat, beurre de cacahuète, noix, fromage");
}

// ============================================
// 7. NOTES ANALYSIS (Free text feedback)
// ============================================
const notesLower = (notes || "").toLowerCase();

if (notesLower.includes("fatigué") || notesLower.includes("fatigue") || notesLower.includes("épuisé")) {
  if (carbs_adjustment === 0) {
    carbs_adjustment += 20;
    rationale.push("Fatigue mentionnée → +20g glucides");
  }
  tips.push("La fatigue peut venir du manque de calories, glucides, fer ou sommeil");
}

if (notesLower.includes("ballonné") || notesLower.includes("digestion") || notesLower.includes("ventre")) {
  tips.push("Problèmes digestifs: réduis les fibres temporairement, mange plus lentement");
  tips.push("Tiens un journal alimentaire pour identifier les aliments problématiques");
}

if (notesLower.includes("motivation") || notesLower.includes("difficile") || notesLower.includes("dur")) {
  tips.push("La motivation fluctue - concentre-toi sur les habitudes, pas la perfection");
  tips.push("Autorise-toi 1-2 repas plaisir par semaine pour tenir sur le long terme");
}

// ============================================
// 8. METABOLIC TENDENCY (after 4+ weeks)
// ============================================
if (weeks_on_plan >= 4) {
  alerts.push("📊 4+ semaines complétées - Analyse de tendance métabolique disponible");
  tips.push("Après 4 semaines, on peut détecter si ton métabolisme est rapide, normal ou lent");
}

// ============================================
// 9. CALCULATE NEW TARGETS
// ============================================
const new_calories = Math.round(current_calories + calorie_adjustment);
const new_protein = Math.round(current_protein_g + protein_adjustment);
const new_carbs = Math.round(current_carbs_g + carbs_adjustment);
const new_fat = Math.round(current_fat_g + fat_adjustment);

// Safety floors
const final_calories = Math.max(new_calories, 1200);
const final_protein = Math.max(new_protein, 50);
const final_carbs = Math.max(new_carbs, 50);
const final_fat = Math.max(new_fat, 30);

// ============================================
// 10. GENERATE STATUS & RECOMMENDATION
// ============================================
let status = "stable";
if (Math.abs(calorie_adjustment) > 150) {
  status = calorie_adjustment > 0 ? "increase_significant" : "decrease_significant";
} else if (calorie_adjustment !== 0) {
  status = calorie_adjustment > 0 ? "increase_minor" : "decrease_minor";
}

let recommendation = "";
const goalMessages = {
  weight_loss: {
    optimal: "🎯 Progression idéale ! Continue comme ça.",
    increase: "📈 Léger ajustement à la hausse pour un déficit soutenable.",
    decrease: "📉 Léger ajustement à la baisse pour relancer la perte."
  },
  muscle_gain: {
    optimal: "💪 Prise de masse propre en cours ! Continue.",
    increase: "📈 Augmente les calories pour favoriser la croissance musculaire.",
    decrease: "📉 Réduis légèrement pour limiter la prise de gras."
  },
  performance: {
    optimal: "🏆 Équilibre parfait pour la performance !",
    increase: "📈 Plus d'énergie nécessaire pour tes entraînements.",
    decrease: "📉 Léger ajustement pour optimiser la composition corporelle."
  },
  maintenance: {
    optimal: "⚖️ Maintien parfait !",
    increase: "📈 Léger ajustement pour stabiliser.",
    decrease: "📉 Léger ajustement pour stabiliser."
  }
};

const goalKey = goalLower.includes("perte") || goalLower.includes("loss") ? "weight_loss" :
                goalLower.includes("muscle") || goalLower.includes("masse") || goalLower.includes("prise") ? "muscle_gain" :
                goalLower.includes("performance") || goalLower.includes("sport") ? "performance" : "maintenance";

if (calorie_adjustment === 0 && protein_adjustment === 0 && carbs_adjustment === 0) {
  recommendation = goalMessages[goalKey].optimal;
} else if (calorie_adjustment > 0) {
  recommendation = goalMessages[goalKey].increase;
} else {
  recommendation = goalMessages[goalKey].decrease;
}

// ============================================
// 11. RETURN RESULTS
// ============================================
return JSON.stringify({
  status: status,

  adjustments: {
    calories: calorie_adjustment,
    protein_g: protein_adjustment,
    carbs_g: carbs_adjustment,
    fat_g: fat_adjustment
  },

  current_targets: {
    calories: current_calories,
    protein_g: current_protein_g,
    carbs_g: current_carbs_g,
    fat_g: current_fat_g
  },

  new_targets: {
    calories: final_calories,
    protein_g: final_protein,
    carbs_g: final_carbs,
    fat_g: final_fat
  },

  weight_analysis: {
    start_kg: weight_start,
    end_kg: weight_end,
    change_kg: parseFloat(weight_change.toFixed(2)),
    change_percent: parseFloat(weight_change_percent),
    trend: weight_change < -0.1 ? "perte" : weight_change > 0.1 ? "prise" : "stable"
  },

  feedback_received: {
    adherence_rate: adherence_rate,
    hunger_level: hunger_level,
    energy_level: energy_level,
    sleep_quality: sleep_quality,
    cravings: cravings,
    user_goal: user_goal,
    weeks_on_plan: weeks_on_plan
  },

  rationale: rationale,
  alerts: alerts.length > 0 ? alerts : ["✅ Aucune alerte"],
  warnings: warnings.length > 0 ? warnings : [],
  tips: tips.length > 0 ? tips : ["Continue comme ça !"],

  recommendation: recommendation,

  next_steps: [
    calorie_adjustment !== 0 ? `Ajuster les calories: ${calorie_adjustment > 0 ? '+' : ''}${calorie_adjustment} kcal → ${final_calories} kcal` : null,
    protein_adjustment !== 0 ? `Ajuster les protéines: ${protein_adjustment > 0 ? '+' : ''}${protein_adjustment}g → ${final_protein}g` : null,
    carbs_adjustment !== 0 ? `Ajuster les glucides: ${carbs_adjustment > 0 ? '+' : ''}${carbs_adjustment}g → ${final_carbs}g` : null,
    fat_adjustment !== 0 ? `Ajuster les lipides: ${fat_adjustment > 0 ? '+' : ''}${fat_adjustment}g → ${final_fat}g` : null,
    hungerLower === "high" || hungerLower === "élevé" ? "Ajouter des aliments rassasiants (protéines, fibres)" : null,
    energyLower === "low" || energyLower === "faible" ? "Optimiser le timing des glucides autour des entraînements" : null,
    sleepLower === "poor" || sleepLower === "mauvais" ? "PRIORITÉ: Améliorer la qualité du sommeil" : null
  ].filter(Boolean),

  summary: `Semaine ${weeks_on_plan}: ${weight_change >= 0 ? '+' : ''}${weight_change.toFixed(2)}kg | Adhérence: ${adherence_rate}% | Ajustement: ${calorie_adjustment >= 0 ? '+' : ''}${calorie_adjustment} kcal`

}, null, 2);

const response = $input.first().json;
const content = response.content || response.text || '';

let isValid = false;
let reason = "Impossible d'analyser l'image";

try {
  // Nettoyer la réponse
  const cleanedText = content
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .replace(/\n/g, '')
    .trim();

  const parsed = JSON.parse(cleanedText);
  isValid = parsed.is_valid === true;
  reason = parsed.reason || reason;

} catch (error) {
  // Si le parsing échoue, chercher des mots clés
  const lowerContent = content.toLowerCase();
  if (lowerContent.includes('"is_valid": true') || lowerContent.includes('"is_valid":true')) {
    isValid = true;
  }
  // Extraire la raison si possible
  const reasonMatch = content.match(/"reason":\s*"([^"]+)"/);
  if (reasonMatch) {
    reason = reasonMatch[1];
  }
}

// Récupérer le binary depuis le node précédent (Edit Fields ou Check If Image)
const binaryData = $('Code in JavaScript').first().binary;

return [{
  json: {
    isValid: isValid,
    reason: reason,
    gender: $('Code in JavaScript').first().json.gender || 'male'
  },
  binary: binaryData
}];

const item = $input.first();

// Récupérer les infos JSON
const chatInput = item.json?.chatInput || item.json.body?.chatInput || '';
const sessionId = item.json?.sessionId || item.json.body?.sessionId || '';
const gender = item.json.body?.gender || item.json?.gender || 'male';

// Vérifier si une image est présente dans le JSON
const imageData = item.json?.image || item.json.body?.image || null;

let result = {
  json: {
    chatInput: chatInput,
    sessionId: sessionId,
    hasImage: false,
    gender: gender
  }
};

// Si l'image est dans le JSON (format data:image/xxx;base64,...)
if (imageData && typeof imageData === 'string' && imageData.startsWith('data:image/')) {

  // Extraire le MIME type et les données base64
  const matches = imageData.match(/^data:(image\/[a-zA-Z]+);base64,(.+)$/);

  if (matches) {
    const mimeType = matches[1];
    const base64Data = matches[2];

    result.json.hasImage = true;
    result.binary = {
      data: {
        data: base64Data,
        mimeType: mimeType,
        fileName: 'uploaded_image.' + mimeType.split('/')[1]
      }
    };
  }
}

return [result];
